class Solution {
public:
    string strWithout3a3b(int a, int b) {
        string result;
        while (a > 0 || b > 0) {
            if (a > b) {
                if (a >= 2 && (result.empty() || result.back() != 'a')) {
                    result += "aa";
                    a -= 2;
                } else {
                    result += 'a';
                    a--;
                }
                if (b > 0) {
                    result += 'b';
                    b--;
                }
            } else {
                if (b >= 2 && (result.empty() || result.back() != 'b')) {
                    result += "bb";
                    b -= 2;
                } else {
                    result += 'b';
                    b--;
                }
                if (a > 0) {
                    result += 'a';
                    a--;
                }
            }
        }
        return result;
    }
};

